class Solution {
public:
    bool checkPalindromeFormation(string a, string b) {
        int n = a.size();
        auto isPalindrome = [&](string& s, int l, int r) {
            while (l < r) {
                if (s[l++] != s[r--]) return false;
            }
            return true;
        };

        auto check = [&](string& a, string& b) {
            int l = 0, r = n - 1;
            while (l < r) {
                if (a[l] != b[r]) {
                    return isPalindrome(a, l + 1, r) || isPalindrome(b, l, r - 1);
                }
                l++; r--;
            }
            return true;
        };

        return check(a, b) || check(b, a);
    }
};
```
